import{_ as o,M as r,p as n,q as s,R as e,t as a,N as l,a1 as c}from"./framework-96b046e1.js";const i={},d=c('<p><strong>FreeRTOS</strong> 是市场领先的微控制器和小型微处理器的实时操作系统 <code>(RTOS)</code>，与世界领先的芯片公司合作开发，历时 15 年，现在每 170 秒下载一次。<code>FreeRTOS</code> 在麻省理工学院的开源许可证下免费分发，包括一个内核和越来越多的适用于所有行业领域的库。<code>FreeRTOS</code> 的构建强调可靠性和易用性。</p><p><strong>FreeRTOS</strong> 内核是一个实时操作系统，支持各种架构。它是构建嵌入式微控制器应用程序的理想之选。</p><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>把 <code>FreeRTOS</code> 引入我们的单片机系统后，我们要做的第一件事情就是划分任务，把不同的模块分成不同的任务，任务之间的交互和互动可能会用到 <code>FreeRTOS</code> 中的 <strong>任务通知</strong>、<strong>信号量</strong>、<strong>软件定时器</strong>、<strong>事件组</strong> 等工具。</p><p>我们要把各个任务管理好，任务的<strong>状态</strong>很重要，在什么时候任务应该处于什么状态，应该使用那些工具（<strong>任务通知</strong>、<strong>信号量</strong>等）来调和任务的状态等都很重要。</p></div><p>它提供了以下功能：</p><ul><li>多任务计划程序。</li><li>多个内存分配选项（包括创建完全静态分配的系统的功能）。</li><li>任务间协调基元，包括任务通知、消息队列、多种信号灯类型以及流和消息缓冲区。</li><li>Support 多核微控制器上的对称多处理 (SMP)。</li></ul><h2 id="为什么要学习-rtos" tabindex="-1"><a class="header-anchor" href="#为什么要学习-rtos" aria-hidden="true">#</a> 为什么要学习 RTOS</h2><ul><li>项目复杂功能多</li><li>裸机编程复杂不好维护</li><li>RTOS 容易管理各个任务</li></ul><h2 id="书籍与资料推荐" tabindex="-1"><a class="header-anchor" href="#书籍与资料推荐" aria-hidden="true">#</a> 书籍与资料推荐</h2>',8),p={href:"https://doc.embedfire.com/products/link/zh/latest/tutorial/ebf_freertos_tutorial.html#",target:"_blank",rel:"noopener noreferrer"};function h(_,u){const t=r("ExternalLinkIcon");return n(),s("div",null,[d,e("ul",null,[e("li",null,[e("a",p,[a("FreeRTOS 内核实现与应用开发实战指南"),l(t)])])])])}const f=o(i,[["render",h],["__file","index.html.vue"]]);export{f as default};
